@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
}

.cw-root {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  padding: 0.5rem;
}

.cw-top {
  display: flex;
  gap: 1.5rem;
}

.cw-fields {
  flex: 0 0 260px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  border-right: 1px solid rgba(0, 0, 0, 0.08);
  padding-right: 1.5rem;
}

.field-label {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  display: block;
  margin-bottom: 4px;
}

.field-box {
  background: rgba(5, 4, 46, 0.04);
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  padding: 8px 10px;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  min-height: 18px;
}

.cw-right {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 1rem;
  min-width: 0;
}

.dial-tiles {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
}

.dial-tile {
  background: rgba(5, 4, 46, 0.04);
  border-radius: 8px;
  padding: 10px 12px;
}

.dial-tile.warn {
  background: #FEE2E2;
  border: 0.5px solid #FCA5A5;
}

.dial-tile-label {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #888780;
  margin-bottom: 5px;
}

.dial-tile.warn .dial-tile-label {
  color: #991B1B;
}

.dial-badge {
  display: inline-flex;
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
  background: rgba(163, 232, 81, 0.2);
  color: #4c7a1a;
}

.dial-badge.warn {
  background: #F7C1C1;
  color: #791F1F;
}

.status-summary-row {
  display: flex;
  gap: 1.5rem;
}

.status-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  border-right: 1px solid rgba(70, 155, 192, 0.2);
  padding-right: 1.5rem;
}

.progress-ring-wrap {
  position: relative;
  width: 110px;
  height: 110px;
}

.progress-label {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.progress-pct {
  font-size: 18px;
  font-weight: 700;
  color: #05042E;
}

.progress-sub {
  font-size: 10px;
  color: #888780;
}

.stage-list {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.stage-row {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 5px 8px;
  border-radius: 6px;
}

.stage-row.current {
  background: rgba(70, 155, 192, 0.08);
  border: 1px solid #469BC0;
}

.stage-dot {
  width: 16px;
  height: 16px;
  border-radius: 50%;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  color: #fff;
