.stage-dot.done {
  background: #469BC0;
}

.stage-dot.current {
  background: #fff;
  border: 2px solid #469BC0;
}

.stage-dot.upcoming {
  background: #e5e7eb;
}

.stage-text {
  font-size: 11px;
}

.stage-text.done {
  color: #469BC0;
