const STAGES = ['Booked', 'Collected', 'Received', 'Booking In', 'All Assets Booked', 'Processing/Pricing', 'Complete'];
let currentModel = {};

function formatDate(dateStr) {
  if (!dateStr) return '—';
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return '—';
  return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
}

function getInitials(name) {
  if (!name) return '?';
  return name.trim().split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
}

window.advanceStatus = function () {
  document.getElementById('btn-advance').disabled = true;
  document.getElementById('btn-advance').textContent = 'Updating...';
  appsmith.triggerEvent('onAdvanceStatus');
};

window.startBooking = function () {
  appsmith.triggerEvent('onStartBooking');
};

window.viewAssets = function () {
  appsmith.triggerEvent('onViewAssets');
};

window.distributeMiscCost = function () {
  const val = document.getElementById('misc-cost-input').value;
  appsmith.updateModel({ miscCost: val });
  appsmith.triggerEvent('onDistributeMisc');
};

function renderFinancials(m) {
  const s = typeof m.summary === 'string' ? JSON.parse(m.summary) : (m.summary || {});
  const typedVal = parseFloat(document.getElementById('misc-cost-input').value);
  const isLivePreview = !isNaN(typedVal) && typedVal > 0;
  const miscCost = isLivePreview ? typedVal : (parseFloat(s.carriage_cost) || 0);

  const sales = parseFloat(s.sales_total) || 0;
  const fees = parseFloat(s.sales_fees) || 0;
  const cost = parseFloat(s.total_cost) || 0;
  const parts = parseFloat(s.parts_cost) || 0;
  const gp = sales - fees - cost - parts - miscCost;

  document.getElementById('financial-rows').innerHTML = [
    ['Sales', sales, false, false],
    ['Sales Fees', fees, true, false],
    ['Cost', cost, true, false],
    ['Parts', parts, true, false],
    ['Misc cost', miscCost, !isLivePreview, isLivePreview]
  ].map(([label,val,isCost,isLive]) => `<div class="metric-row ${isCost ? 'cost' : ''} ${isLive ? 'live' : ''}"><span class="metric-label">${label}</span><span class="metric-value">£${val.toLocaleString('en-GB',{minimumFractionDigits:2})}</span></div>`).join('');

  document.getElementById('gross-profit-row').className = 'gross-profit-row' + (gp < 0 ? ' negative' : '');
  document.getElementById('gross-profit-row').innerHTML = `<span class="gross-profit-label">Gross Profit</span><span class="gross-profit-value">£${gp.toLocaleString('en-GB',{minimumFractionDigits:2})}</span>`;
}

function render(m) {
  currentModel = m;

  document.getElementById('f-date-created').textContent = formatDate(m.date_created);
  document.getElementById('f-created-by').textContent = m.created_by || '—';
  document.getElementById('f-customer').textContent = m.customer_name || '—';
  document.getElementById('f-address1').textContent = m.address1 || '—';
  document.getElementById('f-address2').textContent = m.address2 || '—';
  document.getElementById('f-city').textContent = m.city || '—';
  document.getElementById('f-postcode').textContent = m.postcode || '—';

  const now = new Date(); now.setHours(0,0,0,0);
  const expiry = m.dial_expiry ? new Date(String(m.dial_expiry).split(' ')[0]) : null;
  const isExpired = expiry && !isNaN(expiry.getTime()) && expiry < now;
  const msaOk = m.msa_signed === 'Yes' || m.msa_signed === true || m.msa_signed === 'true';

  document.getElementById('dial-tiles').innerHTML = `
    <div class="dial-tile ${isExpired ? 'warn' : ''}">
      <div class="dial-tile-label">Dial ref</div>
      <span class="dial-badge">${m.dial_ref || 'N/A'}</span>
    </div>
    <div class="dial-tile ${isExpired ? 'warn' : ''}">
      <div class="dial-tile-label">Dial expiry</div>
      <span class="dial-badge ${isExpired ? 'warn' : ''}">${formatDate(m.dial_expiry)}</span>
    </div>
    <div class="dial-tile">
      <div class="dial-tile-label">MSA signed</div>
      <span class="dial-badge ${msaOk ? '' : 'warn'}">${msaOk ? 'Yes' : 'No'}</span>
    </div>`;

  const current = m.current_status;
  const currentIndex = STAGES.indexOf(current);
  const next = currentIndex >= 0 && currentIndex < STAGES.length - 1 ? STAGES[currentIndex + 1] : null;
  const progress = currentIndex >= 0 ? Math.round(((currentIndex + 1) / STAGES.length) * 100) : 0;

  document.getElementById('progress-pct').textContent = progress + '%';
  document.getElementById('progress-arc').setAttribute('stroke-dasharray', ((progress/100)*377) + ' 377');

  document.getElementById('stage-list').innerHTML = STAGES.map((stage, i) => {
    const isDone = i < currentIndex;
    const isCurrent = i === currentIndex;
    const cls = isDone ? 'done' : (isCurrent ? 'current' : 'upcoming');
    return `<div class="stage-row ${isCurrent ? 'current' : ''}">
      <div class="stage-dot ${cls}">${isDone ? '✓' : ''}</div>
      <span class="stage-text ${cls}">${stage}</span>
    </div>`;
  }).join('');

  const advBtn = document.getElementById('btn-advance');
  advBtn.disabled = false;
  if (next) {
    advBtn.style.display = 'block';
    advBtn.textContent = next === 'Booking In' ? 'Start booking process' : `Mark as "${next}"`;
  } else {
    advBtn.style.display = 'none';
  }

  document.getElementById('units-rows').innerHTML = (function() {
    const s = typeof m.summary === 'string' ? JSON.parse(m.summary) : (m.summary || {});
    return [
      ['Expected', s.expected_units || 0],
      ['Received', s.received || 0],
      ['Available for Sale', s.available_for_sale || 0],
      ['Sold', s.sold_count || 0],
      ['Recycled', s.recycled || 0]
    ].map(([label,val]) => `<div class="metric-row"><span class="metric-label">${label}</span><span class="metric-value">${val}</span></div>`).join('');
  })();

  renderFinancials(m);

  const hasContact = m.site_contact || m.contact_number || m.contact_email;
  const contactEl = document.getElementById('site-contact');
  if (!hasContact) {
    contactEl.innerHTML = `<div style="text-align:center;color:#888780;font-size:13px;padding:1rem 0;">No site contact recorded</div>`;
  } else {
    contactEl.innerHTML = `
      <div style="display:flex;align-items:center;gap:12px;padding:10px 12px;background:rgba(5,4,46,0.03);border-radius:8px;margin-bottom:10px;">
        <div style="width:40px;height:40px;border-radius:50%;background:#E1F5EE;color:#085041;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;border:1.5px solid #B6E4D4;">${getInitials(m.site_contact)}</div>
        <div>
          <div style="font-size:14px;font-weight:600;color:#05042E;">${m.site_contact || '—'}</div>
          <div style="font-size:12px;color:#888780;margin-top:2px;">Site contact — may differ from main contact</div>
        </div>
      </div>
      <div style="display:flex;gap:24px;font-size:13px;">
        <div><span style="color:#888780;">Phone: </span><span style="color:#05042E;font-weight:600;">${m.contact_number || '—'}</span></div>
        <div><span style="color:#888780;">Email: </span><span style="color:#05042E;font-weight:600;">${m.contact_email || '—'}</span></div>
      </div>`;
  }
}

appsmith.onReady(function () {
  render(appsmith.model);
  document.getElementById('misc-cost-input').addEventListener('input', function () {
    renderFinancials(currentModel);
  });
});
appsmith.onModelChange(function (m) { render(m); });
